import { reportHandoff } from "../analytics.js";
import { runBrowserHandoff } from "../browserHandoff.js";
import { getConfig, hasCredentials } from "../config.js";
import { focusApp, getFrontmostApp } from "../frontmostApp.js";
const START_TEMPLATE_PREVIEW_TIMEOUT_MS = 30 * 60 * 1000;
const RESPONSE_HTML = `<html>
<body style="margin:0;background:#f8fafc;color:#0f172a;font-family:system-ui,-apple-system,sans-serif;display:flex;align-items:center;justify-content:center;height:100vh;overflow:hidden">
  <div style="text-align:center;max-width:400px">
    <h1 style="font-size:24px;font-weight:600;margin:0 0 16px 0">Bitfab</h1>
    <p style="margin:0;color:#059669">Template editing complete! You can close this window.</p>
    <button onclick="window.close()" style="margin-top:16px;padding:8px 16px;background:#0f172a;color:white;border:none;border-radius:8px;font-size:14px;font-weight:500;cursor:pointer">Close Window</button>
  </div>
</body>
</html>`;
export function buildTemplatePreviewUrl(serviceUrl, functionKey) {
    return `${serviceUrl}/plugin/trace-functions/${encodeURIComponent(functionKey)}/template-preview`;
}
/**
 * Open the chromeless template-preview page for one trace function and stay
 * alive until the user clicks Close on the page (or the timeout elapses).
 * Mirrors `runStartDataset` minus the agent-event poller — the templates flow
 * doesn't have non-terminal events to forward back, just a single "user is
 * done" terminal signal.
 *
 * The calling agent runs this in the background (Claude Code:
 * `run_in_background: true`) so it can keep iterating on templates over MCP
 * while the page stays open. When the background process exits, the loop
 * knows the user clicked Close.
 *
 * Usage: startTemplatePreview <functionKey>
 */
export async function runStartTemplatePreview(platform, pluginVersion) {
    const args = process.argv.slice(2);
    const functionKey = args[0];
    if (!functionKey) {
        console.error("Usage: startTemplatePreview <functionKey>");
        console.error("Function key is required.");
        process.exit(1);
    }
    if (!hasCredentials()) {
        console.error(`Not authenticated. Run ${platform.loginHint} first.`);
        process.exit(1);
    }
    const config = getConfig();
    if (!config.apiKey) {
        console.error("API key missing in config.");
        process.exit(1);
    }
    const apiKey = config.apiKey;
    const previousApp = getFrontmostApp();
    const loopbackRoute = {
        path: "/done",
        handle: (params, res, resolve) => {
            res.writeHead(200, { "Content-Type": "text/html" });
            res.end(RESPONSE_HTML);
            resolve({
                status: "closed",
                isFetch: params.get("isFetch") === "true",
            });
        },
    };
    try {
        const { value, wonBy, loopbackAvailable, ticketAvailable } = await runBrowserHandoff({
            serviceUrl: config.serviceUrl,
            ticketKind: "template.preview",
            ticketBearer: apiKey,
            timeoutMs: START_TEMPLATE_PREVIEW_TIMEOUT_MS,
            ticketTtlSeconds: START_TEMPLATE_PREVIEW_TIMEOUT_MS / 1000,
            buildUrl: ({ port, ticketId }) => {
                const url = new URL(buildTemplatePreviewUrl(config.serviceUrl, functionKey));
                if (port !== null) {
                    url.searchParams.set("callbackPort", String(port));
                }
                if (ticketId !== null) {
                    url.searchParams.set("ticket", ticketId);
                }
                return url.toString();
            },
            loopbackRoutes: [loopbackRoute],
        });
        console.log(`Template preview closed [via ${wonBy}].`);
        await reportHandoff(apiKey, pluginVersion, platform, {
            flow: "template.preview",
            wonBy: wonBy,
            loopbackAvailable,
            ticketAvailable,
        });
        if (value.isFetch) {
            focusApp(previousApp);
        }
        process.exit(0);
    }
    catch (err) {
        console.error(err.message);
        process.exit(1);
    }
}
